function sha256(bytes) {
  function rrot(x, n) { return (x >>> n) | (x << (32 - n)); }
  const K = [0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
  let H = [0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19];
  const b = bytes.slice();
  const bitLen = b.length * 8;
  b.push(0x80);
  while (b.length % 64 !== 56) b.push(0);
  for (let i = 7; i >= 0; i--) b.push((bitLen / Math.pow(2, i * 8)) & 0xff);
  for (let chunk = 0; chunk < b.length; chunk += 64) {
    const w = new Array(64).fill(0);
    for (let i = 0; i < 16; i++) w[i] = ((b[chunk+i*4]<<24)|(b[chunk+i*4+1]<<16)|(b[chunk+i*4+2]<<8)|(b[chunk+i*4+3]))>>>0;
    for (let i = 16; i < 64; i++) {
      const s0 = rrot(w[i-15],7) ^ rrot(w[i-15],18) ^ (w[i-15] >>> 3);
      const s1 = rrot(w[i-2],17) ^ rrot(w[i-2],19) ^ (w[i-2] >>> 10);
      w[i] = (w[i-16] + s0 + w[i-7] + s1) >>> 0;
    }
    let [a,c2,c3,d,e,f,g,h] = H;
    for (let i = 0; i < 64; i++) {
      const S1 = rrot(e,6) ^ rrot(e,11) ^ rrot(e,25);
      const ch = (e & f) ^ (~e & g);
      const t1 = (h + S1 + ch + K[i] + w[i]) >>> 0;
      const S0 = rrot(a,2) ^ rrot(a,13) ^ rrot(a,22);
      const maj = (a & c2) ^ (a & c3) ^ (c2 & c3);
      const t2 = (S0 + maj) >>> 0;
      h=g; g=f; f=e; e=(d+t1)>>>0; d=c3; c3=c2; c2=a; a=(t1+t2)>>>0;
    }
    H = [(H[0]+a)>>>0,(H[1]+c2)>>>0,(H[2]+c3)>>>0,(H[3]+d)>>>0,(H[4]+e)>>>0,(H[5]+f)>>>0,(H[6]+g)>>>0,(H[7]+h)>>>0];
  }
  const out = [];
  for (const n of H) out.push((n>>>24)&0xff,(n>>>16)&0xff,(n>>>8)&0xff,n&0xff);
  return out;
}
function toBytes(str) { return Array.from(Buffer.from(str, 'utf8')); }
function hmacSha256Hex(key, message) {
  const blockSize = 64;
  let keyBytes = toBytes(key);
  if (keyBytes.length > blockSize) keyBytes = sha256(keyBytes);
  if (keyBytes.length < blockSize) keyBytes = keyBytes.concat(new Array(blockSize - keyBytes.length).fill(0));
  const opad = keyBytes.map(byte => byte ^ 0x5c);
  const ipad = keyBytes.map(byte => byte ^ 0x36);
  const inner = sha256(ipad.concat(toBytes(message)));
  const outer = sha256(opad.concat(inner));
  return outer.map(b => b.toString(16).padStart(2, '0')).join('');
}
function timingSafeEqual(a, b) {
  if (a.length !== b.length) return false;
  let diff = 0;
  for (let i = 0; i < a.length; i++) diff |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return diff === 0;
}

const secret = '179c426bfdb5ec176d55e1f4893655598fc90bcb45d75fd839370eb8cf5bb88a';
const signatureHeader = $('Webhook: /strategy-call').first().json.headers['x-velor-signature'];
const body = JSON.stringify($input.first().json.body ?? $input.first().json);

let signatureValid = false;
if (secret && signatureHeader) {
  const expected = hmacSha256Hex(secret, body);
  signatureValid = timingSafeEqual(expected, signatureHeader);
}

const b = $input.first().json.body ?? $input.first().json;
const durationMin = Number(60 || 60);
const bufferMin = Number(15 || 15);
const timezone = 'America/Toronto' || 'America/Toronto';

return [{ json: { ...b, signatureValid, durationMin, bufferMin, timezone, slotKey: `${timezone}|${b.meetingDate}|${b.meetingTime}` } }];

const parsed = $('Verify Signature & Parse Input').first().json;
const rows = $input.first().json.values || [];
const match = rows.find(r => r[50] === parsed.submissionId);
return [{ json: { ...parsed, existingBookingId: match ? match[0] : null, existingStatus: match ? match[3] : null, existingCalendarLink: match ? match[26] : null, existingMeetLink: match ? match[27] : null } }];

const parsed = $('Check Existing Submission').first().json;
const rows = $input.first().json.values || [];
const withIndex = rows.map((r, i) => ({ slotKey: r[0], submissionId: r[1], lockedAt: r[2], rowNumber: i + 2 }));
const matching = withIndex.filter(r => r.slotKey === parsed.slotKey);
matching.sort((a, b) => new Date(a.lockedAt) - new Date(b.lockedAt));
const ours = withIndex.find(r => r.submissionId === parsed.submissionId);
const weOwnIt = matching.length > 0 && matching[0].submissionId === parsed.submissionId;
return [{ json: { ...parsed, weOwnIt, rowNumber: ours ? ours.rowNumber : null } }];

const j = $input.first().json;

function timeZoneOffsetMinutes(instant, timeZone) {
  const dtf = new Intl.DateTimeFormat('en-US', { timeZone, hourCycle: 'h23', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', second: '2-digit' });
  const parts = dtf.formatToParts(instant).reduce((acc, p) => { acc[p.type] = p.value; return acc; }, {});
  const asUtc = Date.UTC(+parts.year, +parts.month - 1, +parts.day, +parts.hour, +parts.minute, +parts.second);
  return (asUtc - instant.getTime()) / 60000;
}

function zonedTimeToUtc(isoDate, hour, minute, timeZone) {
  const guess = new Date(`${isoDate}T${String(hour).padStart(2,'0')}:${String(minute).padStart(2,'0')}:00Z`);
  const offset = timeZoneOffsetMinutes(guess, timeZone);
  return new Date(guess.getTime() - offset * 60000);
}

const [_, hh, mm, ampm] = j.meetingTime.match(/(\d+):(\d+)\s*(AM|PM)/i);
let hour = parseInt(hh, 10) % 12;
if (/PM/i.test(ampm)) hour += 12;

const start = zonedTimeToUtc(j.meetingDate, hour, parseInt(mm, 10), j.timezone);
const end = new Date(start.getTime() + j.durationMin * 60000);
const endWithBuffer = new Date(start.getTime() + (j.durationMin + j.bufferMin) * 60000);

const endLabel = new Intl.DateTimeFormat('en-US', { timeZone: j.timezone, hour: 'numeric', minute: '2-digit', hour12: true }).format(end);

return [{ json: { ...j, meetingStartIso: start.toISOString(), meetingEndIso: end.toISOString(), meetingEndWithBufferIso: endWithBuffer.toISOString(), meetingEndLabel: endLabel } }];

const parsed = $('Compute Meeting Window').first().json;
const events = ($input.first().json.items || []).filter(e => e.start && e.end);
const conflict = events.length > 0;
return [{ json: { ...parsed, conflictDetected: conflict } }];

